import React from 'react';
import ParamHeader from './ParamHeader';

function Speed({ speed, onSpeedChange, paramIcons, onIconClick, buttonRefs }) {
  return (
    <div className="bg-white/60 backdrop-blur-sm rounded-2xl p-4 shadow-lg">
      <div className="flex items-center justify-between mb-3">
        <ParamHeader
          paramKey="speed"
          label="速度"
          iconColor="text-blue-500"
          onIconClick={onIconClick}
          buttonRef={(el) => buttonRefs.current.speed = el}
        />
      </div>
      <div className="flex gap-2">
        {[1, 2, 3, 4, 5].map((speedOption) => (
          <button
            key={speedOption}
            onClick={() => onSpeedChange(speedOption)}
            className={`flex-1 py-2 rounded-xl font-bold transition-all ${
              speed === speedOption
                ? 'bg-gradient-to-r from-blue-400 to-cyan-400 text-white shadow-lg scale-110'
                : 'bg-white/80 text-gray-600 hover:bg-white hover:scale-105'
            }`}
          >
            {speedOption}
          </button>
        ))}
      </div>
    </div>
  );
}

export default Speed;
